arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX [ValidateScopes]: Changed from Singleton to Scoped.
// .NET 9 enables ValidateScopes in development by default. A Singleton
// capturing a Scoped service (captive dependency) now throws at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// FIX [SocketsHttpHandler]: .NET 9 HttpClientFactory uses SocketsHttpHandler
// by default. The previous cast to HttpClientHandler throws InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });
// FIX [Header redaction]: .NET 9 redacts all header values in Trace-level
// HttpClientFactory logs by default. Allowlist non-sensitive headers needed
// for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Cache-Control"
        && h != "Accept"
        && h != "Content-Type"));
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // FIX [Forwarded Headers]: .NET 9 ignores X-Forwarded-* headers from
    // proxies not in KnownProxies or KnownNetworks. Add your reverse proxy
    // address below.
    // options.KnownProxies.Add(IPAddress.Parse("10.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

